Event Start
LoadWWPContext.Call(&Context) padraoUsuario.Call('L', 'HAVERSERLECIONADO_FCHDV', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod) &sdtPagamentoDuplicata.FromJson(&PadObs) padraoUsuario.Call('L', 'CONTAHAVERSERLECIONADO_CTR', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod) if &PadObs.IsEmpty() &PadObs = trim(Str(&Context.CtaBanCod)) EndIf
//CONTA &SdtContaBancaria = dpContaBancariaNomeFilial_EmpCod.Udp(&Context.EmpCod, &Context.PesCod, &Context.FilCod) GetConfigFormaPagamentoReceber.Call(&Context.EmpCod, &Context.FilCod, &Context.PesCod, 2, &FrpPgtoTip, &FrpPgtoDest, &SdtFormasPagamentoContas, &sdtFormPagamentoLocalCobranca, &SdtFormaPagamentoBandeira) &HaverCtabanCod.Clear() For &SdtFormasPagamentoContasItem in &SdtFormasPagamentoContas //Pagar porque o funcionario esta baixando a Conta pagar. descontando o receber &HaverCtabanCod.AddItem(&SdtFormasPagamentoContasItem.FrpPgtoConCod, &SdtFormasPagamentoContasItem.FrpPgtoConNom) EndFor &HaverCtabanCod = val(&PadObs)
&gridCreVlrSdo.Enabled = 1
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'AttributesSecurityCode'
Grid.Rows = 10 Grid_Empowerer.GridInternalName = Grid.InternalName &CreRecPag = nullvalue(&CreRecPag) &CreSts = nullvalue(&CreSts) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = '#DUPLICATAS EM HAVER NO CONTAS A RECEBER.'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
&CreCliCod = &AuxCreCliCod
EndEvent
Event Refresh
&gridCreVlrSdo.Enabled = 1 &CreCliCod = &AuxCreCliCod
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
Do 'SaveGridState'
&GridCurrentPage = Grid.CurrentPage &GridPageCount = Grid.PageCount
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
padraoUsuario.Call('L', 'HAVERSERLECIONADO_FCHDV', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod) &sdtPagamentoDuplicata.FromJson(&PadObs)
do 'Totaliza'
EndEvent
Event GridPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridPaginationBar.SelectedPage = !'Previous' Grid.PreviousPage() Case GridPaginationBar.SelectedPage = !'Next' Grid.NextPage() Otherwise &PageToGo.FromString(GridPaginationBar.SelectedPage) Grid.GotoPage(&PageToGo) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = GridPaginationBar.RowsPerPageSelectedValue Grid.FirstPage()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Grid.Load
if CreAbvDup.IsEmpty() or CreAbvDup.IsNull() AtualizaSaldoDuplicata.Call(EmpCod, CreCod, FilCod) Endif
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&selecionaDesceleciona.FromImage(DDOMultiselSelOption) &selecionaDesceleciona.TooltipText = ""
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
&AuxCreCod = CreCod do 'IsSelecionado' &selecionaDesceleciona.FromImage(DDOMultiselOption) if &Selecionado = true &selecionaDesceleciona.FromImage(DDOMultiselSelOption) Endif
EndEvent
Event 'DoConfirmaHaver'
//do 'Gravar' Return
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoMarcar'
do 'SelecionaTudo' Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CRECLICOD" &CreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) EndCase EndFor If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Endif
EndSub
Sub 'SaveGridState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"CRECLICOD", "", not &CreCliCod.IsEmpty(), 0, &CreCliCod.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CREVLRSDO", "", not &CreVlrSdo.IsEmpty(), 0, &CreVlrSdo.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CRERECPAG", "", not &CreRecPag.IsEmpty(), 0, &CreRecPag, '') WWP_GridStateAddFilterValue(&GridState, !"CRESTS", "", not &CreSts.IsEmpty(), 0, &CreSts, '')
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Endif
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"DuplicatasCompleto"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AttributesSecurityCode'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
ttbfil.Visible = (1=2)
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Event limpar_campo.Click
&sdtPagamentoDuplicata.Clear() do 'Gravar' do 'Totaliza'
EndEvent
Event &HaverCtabanCod.IsValid
&PadObs = trim(str(&HaverCtabanCod)) padraoUsuario.Call('G', 'CONTAHAVERSERLECIONADO_CTR', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)
EndEvent
Event &selecionaDesceleciona.Click
if &Selecionado = true &selecionaDesceleciona.FromImage(DDOMultiselOption) &Selecionado = false Else &selecionaDesceleciona.FromImage(DDOMultiselSelOption) &Selecionado = true Endif
If CreSts <> Status_Duplicata.CANCELADA If &Selecionado = True
if &gridCreVlrSdo.IsEmpty() &gridCreVlrSdo = CreVlrSdo Endif
if &gridCreVlrSdo > CreVlrSdo &gridCreVlrSdo = CreVlrSdo Endif
// If &IsMostrarJuros = true // CalculaJuros.Call(EmpCod,CreCbrJurCod,CreDtaVct,&CrePagDta, CreVlrSdo,&CreVlrJur, CbrMltVlr, &MoraMoeda) // &CreVlrJur += &MoraMoeda // If &CreVlrJur <> 0 // &CreVlrPgt += &CreVlrJur // EndIF // Endif
// &mensagem = '' // If CreSts = Status_Duplicata.DESCONTADA // CreSts = 'D' = Descontadas // &mensagem += 'DUPLICATAS DESCONTADAS/NEGOCIADAS, NÃO VÃO GERAR CRÉDITOS NO CAIXA!' + NewLine() // Endif
&SdtPagamentoDuplicataItem = new() &SdtPagamentoDuplicataItem.CreCod = CreCod &SdtPagamentoDuplicataItem.FilCod = FilCod &SdtPagamentoDuplicataItem.CreCheCod = CreCheCod &SdtPagamentoDuplicataItem.CreCliCod = CreCliCod &SdtPagamentoDuplicataItem.CreCliRaz = CreCliRaz &SdtPagamentoDuplicataItem.CreCliCodRaz = Trim(str(CreCliCod))+'-'+trim(CreCliRaz)
&SdtPagamentoDuplicataItem.CreVlrPgt = &gridCreVlrSdo &SdtPagamentoDuplicataItem.CrePagVlrJur = 0
&SdtPagamentoDuplicataItem.JurCod = 0 &SdtPagamentoDuplicataItem.CbrMltVlr = 0 &SdtPagamentoDuplicataItem.CreDtaVct = CreDtaVct &SdtPagamentoDuplicataItem.CreVlrSdo = CreVlrSdo // &SdtPagamentoDuplicataItem.CreCbrCod = CreCbrCod // &SdtPagamentoDuplicataItem.CrePedCod = CrePedCod &SdtPagamentoDuplicataItem.CreDupNro = CreDupNro &SdtPagamentoDuplicataItem.CreDtaEms = CreDtaEms //&SdtPagamentoDuplicataItem.CrePagDta = &CrePagDta // &SdtPagamentoDuplicataItem.CreEnvSpc = CreEnvSpc &sdtPagamentoDuplicataItem.MovCpl = trim(str(CreCliCod)) + ' - ' + trim(CreCliRaz) &SdtPagamentoDuplicataItem.CreSts = CreSts &sdtPagamentoDuplicataItem.CrePlanCod = CrePlanCod &sdtPagamentoDuplicataItem.CrePlanCodNomVir = CrePlanCodNomVir &sdtPagamentoDuplicataItem.UtilizaDataVcto = Status_SimNao.Nao &sdtPagamentoDuplicataItem.MovCtaBanCod = 0 &sdtPagamentoDuplicataItem.MovDtaCon = &DataVazia
// VALIDA SERASA // If Not CreEnvSpc.IsEmpty() // &mensagem += 'ATENÇÃO! Cliente:'+ Substr(trim(CreCliRaz), 1, 30) + ' Esta no SPC por esta empresa!' + NewLine() // EndIf
// &SdtPagamentoDuplicataItem.Mensagem = &mensagem
// VALIDA TIPO BAIXA // If &CreTipBxa = TipoDuplicataBaixa.Parcial and &gridCreVlrSdo >= CreVlrSdo // &CreTipBxa = TipoDuplicataBaixa.Total // EndIF // If &CreTipBxa = TipoDuplicataBaixa.Total and &CrevlrPgt < CreVlrSdo // &SdtPagamentoDuplicataItem.CrePagVlrDsc = CreVlrSdo-&CrevlrPgt // EndIf if &gridCreVlrSdo < CreVlrSdo &SdtPagamentoDuplicataItem.CreTipBxa = TipoDuplicataBaixa.Parcial Else &SdtPagamentoDuplicataItem.CreTipBxa = TipoDuplicataBaixa.Total Endif
&SdtPagamentoDuplicata.Add(&SdtPagamentoDuplicataItem) else For &SdtPagamentoDuplicataItem in &SdtPagamentoDuplicata If &SdtPagamentoDuplicataItem.CreCod = CreCod &Index = &SdtPagamentoDuplicata.IndexOf(&SdtPagamentoDuplicataItem) &SdtPagamentoDuplicata.Remove(&Index) Exit EndIF EndFor
// &CreTipBxa = TipoDuplicataBaixa.Total &gridCreVlrSdo = 0 // &CreVlrJur = 0 Endif Else Msg('ATENÇÃO! Esta Duplicata está Cancelada e não pode ser selecionada. Verifique! ') EndIf
// do 'GravaSelecionadas'
// SelecionaDuplicataReceber.Call(EmpCod, FilCod, CreCod, &Context.PesCod, &CrePagDta, &Selecionado, &IsMostrarJuros, &CreVlrJur, &CreVlrPgt, &CreTipBxa, &mensagem, &SdtPagamentoDuplicata) // if &mensagem.IsEmpty() // msg(&mensagem) // Endif
do 'Gravar' do 'Totaliza'
EndEvent
Event &gridCreVlrSdo.IsValid
do 'atualizaSDT'
EndEvent
Sub 'Gravar'
&PadObs = &sdtPagamentoDuplicata.ToJson() padraoUsuario.Call('G', 'HAVERSERLECIONADO_FCHDV', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)
EndSub
Sub 'SelecionaTudo'
&sdtPagamentoDuplicata.Clear() For Each Order EmpCod, FilCod, CreCod Where EmpCod = &Context.EmpCod Where CreCliCod = &CreCliCod Where CreVlrSdo > 0 Where CreRecPag = ReceberPagar.Receber Where CreSts <> Status_Duplicata.CANCELADA
// If CreSts <> Status_Duplicata.CANCELADA // If &Selecionado = True
// if &gridCreVlrSdo.IsEmpty() // &gridCreVlrSdo = CreVlrSdo // Endif // // if &gridCreVlrSdo > CreVlrSdo // &gridCreVlrSdo = CreVlrSdo // Endif
// If &IsMostrarJuros = true // CalculaJuros.Call(EmpCod,CreCbrJurCod,CreDtaVct,&CrePagDta, CreVlrSdo,&CreVlrJur, CbrMltVlr, &MoraMoeda) // &CreVlrJur += &MoraMoeda // If &CreVlrJur <> 0 // &CreVlrPgt += &CreVlrJur // EndIF // Endif
// &mensagem = '' // If CreSts = Status_Duplicata.DESCONTADA // CreSts = 'D' = Descontadas // &mensagem += 'DUPLICATAS DESCONTADAS/NEGOCIADAS, NÃO VÃO GERAR CRÉDITOS NO CAIXA!' + NewLine() // Endif
&SdtPagamentoDuplicataItem = new() &SdtPagamentoDuplicataItem.CreCod = CreCod &SdtPagamentoDuplicataItem.FilCod = FilCod &SdtPagamentoDuplicataItem.CreCheCod = CreCheCod &SdtPagamentoDuplicataItem.CreCliCod = CreCliCod &SdtPagamentoDuplicataItem.CreCliRaz = CreCliRaz &SdtPagamentoDuplicataItem.CreCliCodRaz = Trim(str(CreCliCod))+'-'+trim(CreCliRaz)
&SdtPagamentoDuplicataItem.CreVlrPgt = CreVlrSdo &SdtPagamentoDuplicataItem.CrePagVlrJur = 0
&SdtPagamentoDuplicataItem.JurCod = 0 &SdtPagamentoDuplicataItem.CbrMltVlr = 0 &SdtPagamentoDuplicataItem.CreDtaVct = CreDtaVct &SdtPagamentoDuplicataItem.CreVlrSdo = CreVlrSdo // &SdtPagamentoDuplicataItem.CreCbrCod = CreCbrCod // &SdtPagamentoDuplicataItem.CrePedCod = CrePedCod &SdtPagamentoDuplicataItem.CreDupNro = CreDupNro &SdtPagamentoDuplicataItem.CreDtaEms = CreDtaEms //&SdtPagamentoDuplicataItem.CrePagDta = &CrePagDta // &SdtPagamentoDuplicataItem.CreEnvSpc = CreEnvSpc &sdtPagamentoDuplicataItem.MovCpl = trim(str(CreCliCod)) + ' - ' + trim(CreCliRaz) &SdtPagamentoDuplicataItem.CreSts = CreSts &sdtPagamentoDuplicataItem.CrePlanCod = CrePlanCod &sdtPagamentoDuplicataItem.CrePlanCodNomVir = CrePlanCodNomVir &sdtPagamentoDuplicataItem.UtilizaDataVcto = Status_SimNao.Nao &sdtPagamentoDuplicataItem.MovCtaBanCod = 0 &sdtPagamentoDuplicataItem.MovDtaCon = &DataVazia
// VALIDA SERASA // If Not CreEnvSpc.IsEmpty() // &mensagem += 'ATENÇÃO! Cliente:'+ Substr(trim(CreCliRaz), 1, 30) + ' Esta no SPC por esta empresa!' + NewLine() // EndIf
// &SdtPagamentoDuplicataItem.Mensagem = &mensagem
// VALIDA TIPO BAIXA // If &CreTipBxa = TipoDuplicataBaixa.Parcial and &gridCreVlrSdo >= CreVlrSdo // &CreTipBxa = TipoDuplicataBaixa.Total // EndIF // If &CreTipBxa = TipoDuplicataBaixa.Total and &CrevlrPgt < CreVlrSdo // &SdtPagamentoDuplicataItem.CrePagVlrDsc = CreVlrSdo-&CrevlrPgt // EndIf if &gridCreVlrSdo < CreVlrSdo &SdtPagamentoDuplicataItem.CreTipBxa = TipoDuplicataBaixa.Parcial Else &SdtPagamentoDuplicataItem.CreTipBxa = TipoDuplicataBaixa.Total Endif
&SdtPagamentoDuplicata.Add(&SdtPagamentoDuplicataItem) // else // For &SdtPagamentoDuplicataItem in &SdtPagamentoDuplicata // If &SdtPagamentoDuplicataItem.CreCod = CreCod // &Index = &SdtPagamentoDuplicata.IndexOf(&SdtPagamentoDuplicataItem) // &SdtPagamentoDuplicata.Remove(&Index) // Exit // EndIF // EndFor // // // &CreTipBxa = TipoDuplicataBaixa.Total // &gridCreVlrSdo = 0 // // &CreVlrJur = 0 // Endif // Else // Msg('ATENÇÃO! Esta Duplicata está Cancelada e não pode ser selecionada. Verifique! ') // EndIf
EndFor
do 'Gravar'
EndSub
Sub 'Totaliza'
&TotalhaverMoeda = 0 For &SdtpagamentoDuplicataItem in &sdtPagamentoDuplicata &TotalhaverMoeda += &SdtpagamentoDuplicataItem.CreVlrPgt EndFor
EndSub
Sub 'IsSelecionado'
&Selecionado = false
For &SdtpagamentoDuplicataItem in &SdtpagamentoDuplicata If &SdtpagamentoDuplicataItem.CreCod = &AuxCreCod &Selecionado = true &gridCreVlrSdo = &SdtpagamentoDuplicataItem.CreVlrPgt //&CreVlrJur = &SdtpagamentoDuplicataItem.CrePagVlrJur exit EndIf EndFor
EndSub
Sub 'atualizaSDT'
if &gridCreVlrSdo > CreVlrSdo &gridCreVlrSdo = CreVlrSdo EndIf
For &SdtpagamentoDuplicataItem in &SdtpagamentoDuplicata If &SdtpagamentoDuplicataItem.CreCod = CreCod
if &gridCreVlrSdo < CreVlrSdo &SdtPagamentoDuplicataItem.CreTipBxa = TipoDuplicataBaixa.Parcial Else &SdtPagamentoDuplicataItem.CreTipBxa = TipoDuplicataBaixa.Total Endif
&SdtpagamentoDuplicataItem.CreVlrPgt = &gridCreVlrSdo // &SdtpagamentoDuplicataItem.CrePagVlrJur = &CreVlrJur // &SdtpagamentoDuplicataItem.CrePagVlrDsc = &CreVlrDsc &SdtpagamentoDuplicataItem.CrePlanCod = CrePlanCod &sdtPagamentoDuplicataItem.CrePlanCodNomVir = CrePlanCodNomVir Exit EndIf EndFor
do 'Gravar' do 'Totaliza'
EndSub
